    private void retrieveData() {
    DefaultTableModel model = (DefaultTableModel) jTable1.getModel();
    model.setRowCount(0); // Clear existing rows in the table
    
    try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/java", "root", "root")) {
        String query = "SELECT * FROM java_student_info"; // Adjust to your table name if necessary
        try (Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery(query)) {
            while (rs.next()) {
                String studentID = rs.getString("StudentID");
                String fullname = rs.getString("Fullname");
                double sub1 = rs.getDouble("Sub1");
                double sub2 = rs.getDouble("Sub2");
                double sub3 = rs.getDouble("Sub3");
                double sub4 = rs.getDouble("Sub4");
                double sub5 = rs.getDouble("Sub5");
                double sub6 = rs.getDouble("Sub6");
                double sub7 = rs.getDouble("Sub7");
                double sub8 = rs.getDouble("Sub8");
                double gpa = rs.getDouble("GPA");

                // Add row to the JTable
                model.addRow(new Object[]{studentID, fullname, sub1, sub2, sub3, sub4, sub5, sub6, sub7, sub8, gpa});
            }
        }
    } catch (SQLException e) {
        JOptionPane.showMessageDialog(this, "Error retrieving data from database: " + e.getMessage());
    }
}
    

