    private void SaveButtonActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_SaveButtonActionPerformed
        String studentID = jTextField1.getText().trim();
        String fullname = jTextField2.getText().trim();
    // Validate fields
    if (studentID.isEmpty() || fullname.isEmpty()) {
        JOptionPane.showMessageDialog(this, "Student ID and Full Name are required!");
        return;
    }
    double[] scores = new double[8];
    try {
        scores[0] = Double.parseDouble(jTextField3.getText().trim());
        scores[1] = Double.parseDouble(jTextField4.getText().trim());
        scores[2] = Double.parseDouble(jTextField5.getText().trim());
        scores[3] = Double.parseDouble(jTextField6.getText().trim());
        scores[4] = Double.parseDouble(jTextField7.getText().trim());
        scores[5] = Double.parseDouble(jTextField8.getText().trim());
        scores[6] = Double.parseDouble(jTextField9.getText().trim());
        scores[7] = Double.parseDouble(jTextField10.getText().trim());
    } catch (NumberFormatException e) {
        JOptionPane.showMessageDialog(this, "Please enter valid numbers for all subjects!");
        return;
    }
    // Calculate GPA
    double gpa = Arrays.stream(scores).average().orElse(0.0);

    // Database connection
   try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/java", "root", "root")) {
    String query = "INSERT INTO java_student_info (StudentID, Fullname, Sub1, Sub2, Sub3, Sub4, Sub5, Sub6, Sub7, Sub8, GPA) "
                 + "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)";
        try (PreparedStatement pst = conn.prepareStatement(query)) {
            pst.setString(1, studentID);
            pst.setString(2, fullname);
            for (int i = 0; i < 8; i++) {
                pst.setDouble(i + 3, scores[i]); // Set subjects 1-8
            }
            pst.setDouble(11, gpa); // Set GPA
            pst.executeUpdate();
            JOptionPane.showMessageDialog(this, "Record Saved in Database!");
        }
    } catch (SQLException e) {
        JOptionPane.showMessageDialog(this, "Error saving record to database: " + e.getMessage());
    }

    // Add row to the table (optional)
    DefaultTableModel model = (DefaultTableModel) jTable1.getModel();
    model.addRow(new Object[]{studentID, fullname, scores[0], scores[1], scores[2], scores[3], scores[4], scores[5], scores[6], scores[7], gpa});

    JOptionPane.showMessageDialog(this, "Record Saved!");
    }//GEN-LAST:event_SaveButtonActionPerformed

    private void UpdateButtonActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_UpdateButtonActionPerformed
        int selectedRow = jTable1.getSelectedRow();
    if (selectedRow == -1) {
        JOptionPane.showMessageDialog(this, "Please select a row to update!");
        return;
    }

    // Get student ID from the selected row
    String studentID = (String) jTable1.getValueAt(selectedRow, 0);
    
    // Get new values from the input fields
    String fullname = jTextField2.getText().trim();
    double[] scores = new double[8];
    try {
        scores[0] = Double.parseDouble(jTextField3.getText().trim());
        scores[1] = Double.parseDouble(jTextField4.getText().trim());
        scores[2] = Double.parseDouble(jTextField5.getText().trim());
        scores[3] = Double.parseDouble(jTextField6.getText().trim());
        scores[4] = Double.parseDouble(jTextField7.getText().trim());
        scores[5] = Double.parseDouble(jTextField8.getText().trim());
        scores[6] = Double.parseDouble(jTextField9.getText().trim());
        scores[7] = Double.parseDouble(jTextField10.getText().trim());
    } catch (NumberFormatException e) {
        JOptionPane.showMessageDialog(this, "Please enter valid numbers for all subjects!");
        return;
    }
    
    // Calculate GPA
    double gpa = Arrays.stream(scores).average().orElse(0.0);

    // Database connection
    try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/java", "root", "root")) {
        String query = "UPDATE java_student_info SET Fullname = ?, Sub1 = ?, Sub2 = ?, Sub3 = ?, Sub4 = ?, Sub5 = ?, Sub6 = ?, Sub7 = ?, Sub8 = ?, GPA = ? WHERE StudentID = ?";
        try (PreparedStatement pst = conn.prepareStatement(query)) {
            pst.setString(1, fullname);
            for (int i = 0; i < 8; i++) {
                pst.setDouble(i + 2, scores[i]); // Set subjects 1-8
            }
            pst.setDouble(10, gpa); // Set GPA
            pst.setString(11, studentID); // Set the student ID for the WHERE clause
            pst.executeUpdate();
            JOptionPane.showMessageDialog(this, "Record Updated in Database!");
        }
    } catch (SQLException e) {
        JOptionPane.showMessageDialog(this, "Error updating record in database: " + e.getMessage());
    }

    // Update row in the table
    DefaultTableModel model = (DefaultTableModel) jTable1.getModel();
    model.setValueAt(fullname, selectedRow, 1); // Update Full Name
    for (int i = 0; i < 8; i++) {
        model.setValueAt(scores[i], selectedRow, i + 2); // Update subjects 1-8
    }
    model.setValueAt(gpa, selectedRow, 10); // Update GPA

    JOptionPane.showMessageDialog(this, "Record Updated!");
    }//GEN-LAST:event_UpdateButtonActionPerformed

