    private void DeleteButtonActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_DeleteButtonActionPerformed
        int selectedRow = jTable1.getSelectedRow();
    if (selectedRow == -1) {
        JOptionPane.showMessageDialog(this, "Please select a row to delete!");
        return;
    }

    // Get student ID from the selected row
    String studentID = (String) jTable1.getValueAt(selectedRow, 0);

    // Database connection
    try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/java", "root", "root")) {
        String query = "DELETE FROM java_student_info WHERE StudentID = ?";
        try (PreparedStatement pst = conn.prepareStatement(query)) {
            pst.setString(1, studentID); // Set the student ID for the WHERE clause
            pst.executeUpdate();
            JOptionPane.showMessageDialog(this, "Record Deleted from Database!");
        }
    } catch (SQLException e) {
        JOptionPane.showMessageDialog(this, "Error deleting record from database: " + e.getMessage());
    }

    // Remove row from the table
    DefaultTableModel model = (DefaultTableModel) jTable1.getModel();
    model.removeRow(selectedRow);

    JOptionPane.showMessageDialog(this, "Record Deleted!");
    }//GEN-LAST:event_DeleteButtonActionPerformed

